import React from 'react';
/* Import the local button styles */
import './button.css';

// ─────────────────────────────────────────────────────────────
//  TYPES
// ─────────────────────────────────────────────────────────────

export type ButtonVariant =
  | 'solid'
  | 'outline'
  | 'soft'
  | 'ghost'
  | 'link';

export type ButtonColor =
  | 'primary'
  | 'secondary'
  | 'danger'
  | 'success'
  | 'warning'
  | 'info';

export type ButtonSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';

export type ButtonShape = 'default' | 'rounded' | 'square';

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Visual style family. Default: 'solid' */
  variant?: ButtonVariant;

  /** Color token. Default: 'primary' */
  color?: ButtonColor;

  /** Size preset. Default: 'md' */
  size?: ButtonSize;

  /** Border-radius shape. Default: 'default' (8px) */
  shape?: ButtonShape;

  /** Show animated loading spinner and disable the button */
  loading?: boolean;

  /** Text shown next to spinner while loading (falls back to children) */
  loadingText?: string;

  /** Icon rendered before the label */
  iconLeft?: React.ReactNode;

  /** Icon rendered after the label */
  iconRight?: React.ReactNode;

  /** When true, renders an icon-only square/circle button (no label shown) */
  iconOnly?: boolean;

  /** Stretch button to 100% width of its container */
  fullWidth?: boolean;

  /** Notification badge count. Shows a red dot with number over the button */
  badge?: string | number;

  /** Render as a different HTML element (e.g. 'a' for link buttons) */
  as?: React.ElementType;

  /** Extra CSS classes to merge in */
  className?: string;

  children?: React.ReactNode;
}

// ─────────────────────────────────────────────────────────────
//  HELPER — build the CSS class string
// ─────────────────────────────────────────────────────────────

/**
 * Compatibility helper for existing components using shadcn/ui patterns.
 */
export function buttonVariants(props: any = {}): string {
  const variant = props.variant;
  const color = props.color;

  const normalizedProps: ButtonProps = {
    ...props,
    // Map shadcn variants to new names
    variant: (variant === 'default' ? 'solid' : 
              variant === 'destructive' ? 'solid' : 
              variant === 'ghost' ? 'ghost' : 
              variant === 'outline' ? 'outline' : 
              variant === 'secondary' ? 'solid' : 
              variant === 'link' ? 'link' : 
              variant) as ButtonVariant,
    color: (variant === 'destructive' ? 'danger' : 
            variant === 'secondary' ? 'secondary' : 
            color || 'primary') as ButtonColor,
  };
  return buildClassName(normalizedProps);
}

function buildClassName(props: ButtonProps): string {
  const {
    variant  = 'solid',
    color    = 'primary',
    size     = 'md',
    shape    = 'default',
    iconOnly = false,
    fullWidth= false,
    className= '',
  } = props;

  const classes: string[] = ['btn'];

  // size
  classes.push(`btn-${size}`);

  // variant + color class
  if (variant === 'solid') {
    classes.push(`btn-solid-${color}`);
  } else if (variant === 'outline') {
    classes.push(`btn-outline-${color}`);
  } else if (variant === 'soft') {
    classes.push(`btn-soft-${color}`);
  } else if (variant === 'ghost') {
    // ghost maps color to a sub-class; 'primary' uses 'default' to match HTML
    const ghostColor = color === 'primary' ? 'default' : color;
    classes.push(`btn-ghost-${ghostColor}`);
  } else if (variant === 'link') {
    classes.push('btn-link');
  }

  // shape
  if (shape === 'rounded') classes.push('btn-shape-rounded');
  if (shape === 'square')  classes.push('btn-shape-square');

  // modifiers
  if (iconOnly)  classes.push('btn-icon-only');
  if (fullWidth) classes.push('btn-full');

  // consumer's own classes (escape hatch)
  if (className) classes.push(className);

  return classes.join(' ');
}

// ─────────────────────────────────────────────────────────────
//  SPINNER
// ─────────────────────────────────────────────────────────────

function Spinner() {
  return <span className="btn-spinner" aria-hidden="true" />;
}

// ─────────────────────────────────────────────────────────────
//  BUTTON
// ─────────────────────────────────────────────────────────────

/**
 * Button — fully composable, zero-dependency button component.
 */
const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  (props, ref) => {
    const {
      variant      = 'solid',
      color        = 'primary',
      size         = 'md',
      shape        = 'default',
      loading      = false,
      loadingText,
      iconLeft,
      iconRight,
      iconOnly     = false,
      fullWidth    = false,
      badge,
      as           : Tag = 'button',
      className,
      children,
      disabled,
      onClick,
      ...rest
    } = props;

    const isDisabled = disabled || loading;
    const cssClass   = buildClassName({ variant, color, size, shape, iconOnly, fullWidth, className });

    // What renders inside the button
    function renderContent() {
      if (loading) {
        return (
          <>
            <Spinner />
            {!iconOnly && (loadingText ?? children)}
          </>
        );
      }

      if (iconOnly) {
        // icon-only: render iconLeft (or iconRight as fallback), no label
        return iconLeft ?? iconRight ?? null;
      }

      return (
        <>
          {iconLeft  && <span className="btn-icon-wrap" aria-hidden="true">{iconLeft}</span>}
          {children}
          {iconRight && <span className="btn-icon-wrap" aria-hidden="true">{iconRight}</span>}
        </>
      );
    }

    const button = (
      <Tag
        ref={ref}
        className={cssClass}
        disabled={Tag === 'button' ? isDisabled : undefined}
        aria-disabled={isDisabled ? 'true' : undefined}
        onClick={isDisabled ? undefined : onClick}
        {...rest}
      >
        {renderContent()}
      </Tag>
    );

    // Wrap with badge container only when badge prop is provided
    if (badge !== undefined && badge !== null) {
      return (
        <span className="btn-badge-wrap">
          {button}
          <span className="btn-badge">{badge}</span>
        </span>
      );
    }

    return button;
  }
);

Button.displayName = 'Button';

// ─────────────────────────────────────────────────────────────
//  BUTTON GROUP
// ─────────────────────────────────────────────────────────────

export interface ButtonGroupProps {
  children: React.ReactNode;
  className?: string;
}

function ButtonGroup({ children, className = '' }: ButtonGroupProps) {
  return (
    <div className={`btn-group ${className}`.trim()}>
      {children}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
//  BUTTON GROUP ITEM
// ─────────────────────────────────────────────────────────────

export interface ButtonGroupItemProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  active?: boolean;
  size?  : ButtonSize;
  children?: React.ReactNode;
}

function ButtonGroupItem({
  active = false,
  size   = 'md',
  className = '',
  children,
  ...rest
}: ButtonGroupItemProps) {
  const classes = [
    'btn',
    `btn-${size}`,
    'btn-solid-secondary',
    active ? 'btn-group-active' : '',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <button className={classes} {...rest}>
      {children}
    </button>
  );
}

export { Button, ButtonGroup, ButtonGroupItem };
export default Button;

/* ============================================================
   Button.css — All button styles
   Import this once at the top of your app (e.g. in main.tsx
   or App.tsx):  import './Button.css'
   ============================================================ */

/* ── CSS TOKENS ─────────────────────────────────────────── */
:root {
  --btn-font-family    : -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --btn-font-weight    : 500;
  --btn-transition     : all 0.15s ease;
  --btn-focus-shadow   : 0 0 0 3px;

  /* radius scale */
  --btn-radius-default : 8px;
  --btn-radius-pill    : 999px;
  --btn-radius-square  : 4px;

  /* solid colors */
  --color-primary      : #1a1a1a;
  --color-primary-hover: #333333;
  --color-danger       : #dc2626;
  --color-danger-hover : #b91c1c;
  --color-success      : #16a34a;
  --color-success-hover: #15803d;
  --color-warning      : #d97706;
  --color-warning-hover: #b45309;
  --color-info         : #2563eb;
  --color-info-hover   : #1d4ed8;

  /* focus rings */
  --ring-primary       : rgba(0, 0, 0, 0.25);
  --ring-danger        : rgba(220, 38, 38, 0.35);
  --ring-success       : rgba(22, 163, 74, 0.35);
  --ring-warning       : rgba(217, 119, 6, 0.35);
  --ring-info          : rgba(37, 99, 235, 0.35);

  /* surface / neutral */
  --color-surface      : #f3f4f6;
  --color-surface-hover: #e5e7eb;
  --color-border       : #d1d5db;
  --color-text         : #111827;
  --color-text-muted   : #6b7280;
}


/* ── BASE ────────────────────────────────────────────────── */
.btn {
  display         : inline-flex;
  align-items     : center;
  justify-content : center;
  gap             : 6px;
  height          : 38px;
  padding         : 0 16px;
  font-family     : var(--btn-font-family);
  font-size       : 14px;
  font-weight     : var(--btn-font-weight);
  line-height     : 1;
  white-space     : nowrap;
  border          : 1px solid transparent;
  border-radius   : var(--btn-radius-default);
  cursor          : pointer;
  outline         : none;
  text-decoration : none;
  position        : relative;
  overflow        : visible;
  transition      : var(--btn-transition);
  -webkit-user-select: none;
  user-select     : none;
  box-sizing      : border-box;
}

.btn:focus-visible {
  box-shadow: var(--btn-focus-shadow) var(--_ring, var(--ring-primary));
}

.btn:active:not(:disabled) {
  transform: scale(0.97);
}

.btn:disabled,
.btn[aria-disabled="true"] {
  opacity        : 0.45;
  cursor         : not-allowed;
  pointer-events : none;
}

.btn svg {
  flex-shrink: 0;
  display    : block;
}


/* ── SIZES ───────────────────────────────────────────────── */
.btn-xs {
  height       : 26px;
  padding      : 0 10px;
  font-size    : 12px;
  border-radius: var(--btn-radius-square);
  gap          : 4px;
}

.btn-sm {
  height   : 32px;
  padding  : 0 12px;
  font-size: 13px;
}

.btn-md {
  height   : 38px;
  padding  : 0 16px;
  font-size: 14px;
}

.btn-lg {
  height   : 44px;
  padding  : 0 20px;
  font-size: 15px;
  gap      : 8px;
}

.btn-xl {
  height   : 52px;
  padding  : 0 28px;
  font-size: 16px;
  gap      : 10px;
}


/* ── SHAPES ──────────────────────────────────────────────── */
.btn-shape-rounded { border-radius: var(--btn-radius-pill) !important; }
.btn-shape-square  { border-radius: var(--btn-radius-square) !important; }


/* ── ICON-ONLY ───────────────────────────────────────────── */
.btn-icon-only         { padding: 0 !important; }
.btn-icon-only.btn-xs  { width: 26px; }
.btn-icon-only.btn-sm  { width: 32px; }
.btn-icon-only.btn-md  { width: 38px; }
.btn-icon-only.btn-lg  { width: 44px; }
.btn-icon-only.btn-xl  { width: 52px; }


/* ── FULL WIDTH ──────────────────────────────────────────── */
.btn-full { width: 100%; }


/* ══════════════════════════════════════════════════════════
   SOLID VARIANTS
══════════════════════════════════════════════════════════ */

.btn-solid-primary {
  background  : var(--color-primary);
  color       : #ffffff;
  border-color: var(--color-primary);
  --_ring     : var(--ring-primary);
}
.btn-solid-primary:hover:not(:disabled) {
  background  : var(--color-primary-hover);
  border-color: var(--color-primary-hover);
}

.btn-solid-secondary {
  background  : var(--color-surface);
  color       : var(--color-text);
  border-color: var(--color-border);
  --_ring     : var(--ring-primary);
}
.btn-solid-secondary:hover:not(:disabled) {
  background: var(--color-surface-hover);
}

.btn-solid-danger {
  background  : var(--color-danger);
  color       : #ffffff;
  border-color: var(--color-danger);
  --_ring     : var(--ring-danger);
}
.btn-solid-danger:hover:not(:disabled) {
  background  : var(--color-danger-hover);
  border-color: var(--color-danger-hover);
}

.btn-solid-success {
  background  : var(--color-success);
  color       : #ffffff;
  border-color: var(--color-success);
  --_ring     : var(--ring-success);
}
.btn-solid-success:hover:not(:disabled) {
  background  : var(--color-success-hover);
  border-color: var(--color-success-hover);
}

.btn-solid-warning {
  background  : var(--color-warning);
  color       : #ffffff;
  border-color: var(--color-warning);
  --_ring     : var(--ring-warning);
}
.btn-solid-warning:hover:not(:disabled) {
  background  : var(--color-warning-hover);
  border-color: var(--color-warning-hover);
}

.btn-solid-info {
  background  : var(--color-info);
  color       : #ffffff;
  border-color: var(--color-info);
  --_ring     : var(--ring-info);
}
.btn-solid-info:hover:not(:disabled) {
  background  : var(--color-info-hover);
  border-color: var(--color-info-hover);
}


/* ══════════════════════════════════════════════════════════
   OUTLINE VARIANTS
══════════════════════════════════════════════════════════ */

.btn-outline-primary {
  background  : transparent;
  color       : var(--color-primary);
  border-color: var(--color-primary);
  --_ring     : var(--ring-primary);
}
.btn-outline-primary:hover:not(:disabled) {
  background: rgba(0, 0, 0, 0.06);
}

.btn-outline-secondary {
  background  : transparent;
  color       : var(--color-text);
  border-color: var(--color-border);
  --_ring     : var(--ring-primary);
}
.btn-outline-secondary:hover:not(:disabled) {
  background: var(--color-surface);
}

.btn-outline-danger {
  background  : transparent;
  color       : var(--color-danger);
  border-color: var(--color-danger);
  --_ring     : var(--ring-danger);
}
.btn-outline-danger:hover:not(:disabled) {
  background: rgba(220, 38, 38, 0.06);
}

.btn-outline-success {
  background  : transparent;
  color       : var(--color-success);
  border-color: var(--color-success);
  --_ring     : var(--ring-success);
}
.btn-outline-success:hover:not(:disabled) {
  background: rgba(22, 163, 74, 0.06);
}

.btn-outline-warning {
  background  : transparent;
  color       : var(--color-warning);
  border-color: var(--color-warning);
  --_ring     : var(--ring-warning);
}
.btn-outline-warning:hover:not(:disabled) {
  background: rgba(217, 119, 6, 0.06);
}

.btn-outline-info {
  background  : transparent;
  color       : var(--color-info);
  border-color: var(--color-info);
  --_ring     : var(--ring-info);
}
.btn-outline-info:hover:not(:disabled) {
  background: rgba(37, 99, 235, 0.06);
}


/* ══════════════════════════════════════════════════════════
   SOFT VARIANTS
══════════════════════════════════════════════════════════ */

.btn-soft-primary {
  background  : rgba(0, 0, 0, 0.07);
  color       : var(--color-primary);
  border-color: transparent;
}
.btn-soft-primary:hover:not(:disabled) { background: rgba(0, 0, 0, 0.12); }

.btn-soft-secondary {
  background  : var(--color-surface);
  color       : var(--color-text-muted);
  border-color: transparent;
}
.btn-soft-secondary:hover:not(:disabled) { background: var(--color-surface-hover); }

.btn-soft-danger {
  background  : rgba(220, 38, 38, 0.10);
  color       : var(--color-danger-hover);
  border-color: transparent;
  --_ring     : var(--ring-danger);
}
.btn-soft-danger:hover:not(:disabled) { background: rgba(220, 38, 38, 0.16); }

.btn-soft-success {
  background  : rgba(22, 163, 74, 0.10);
  color       : var(--color-success-hover);
  border-color: transparent;
  --_ring     : var(--ring-success);
}
.btn-soft-success:hover:not(:disabled) { background: rgba(22, 163, 74, 0.16); }

.btn-soft-warning {
  background  : rgba(217, 119, 6, 0.10);
  color       : var(--color-warning-hover);
  border-color: transparent;
  --_ring     : var(--ring-warning);
}
.btn-soft-warning:hover:not(:disabled) { background: rgba(217, 119, 6, 0.16); }

.btn-soft-info {
  background  : rgba(37, 99, 235, 0.10);
  color       : var(--color-info-hover);
  border-color: transparent;
  --_ring     : var(--ring-info);
}
.btn-soft-info:hover:not(:disabled) { background: rgba(37, 99, 235, 0.18); }


/* ══════════════════════════════════════════════════════════
   GHOST VARIANTS
══════════════════════════════════════════════════════════ */

.btn-ghost-default {
  background  : transparent;
  color       : var(--color-text);
  border-color: transparent;
}
.btn-ghost-default:hover:not(:disabled) { background: var(--color-surface); }

.btn-ghost-primary {
  background  : transparent;
  color       : var(--color-primary);
  border-color: transparent;
  --_ring     : var(--ring-primary);
}
.btn-ghost-primary:hover:not(:disabled) { background: rgba(0, 0, 0, 0.06); }

.btn-ghost-danger {
  background  : transparent;
  color       : var(--color-danger);
  border-color: transparent;
  --_ring     : var(--ring-danger);
}
.btn-ghost-danger:hover:not(:disabled) { background: rgba(220, 38, 38, 0.06); }

.btn-ghost-info {
  background  : transparent;
  color       : var(--color-info);
  border-color: transparent;
  --_ring     : var(--ring-info);
}
.btn-ghost-info:hover:not(:disabled) { background: rgba(37, 99, 235, 0.06); }

.btn-ghost-success {
  background  : transparent;
  color       : var(--color-success);
  border-color: transparent;
  --_ring     : var(--ring-success);
}
.btn-ghost-success:hover:not(:disabled) { background: rgba(22, 163, 74, 0.06); }


/* ══════════════════════════════════════════════════════════
   LINK VARIANT
══════════════════════════════════════════════════════════ */

.btn-link {
  background           : transparent;
  border-color         : transparent;
  color                : var(--color-info);
  padding              : 0 4px;
  height               : auto;
  text-decoration      : underline;
  text-underline-offset: 2px;
  --_ring              : var(--ring-info);
}
.btn-link:hover:not(:disabled) {
  color          : var(--color-info-hover);
  text-decoration: underline;
}


/* ══════════════════════════════════════════════════════════
   LOADING SPINNER
══════════════════════════════════════════════════════════ */

.btn-spinner {
  display      : inline-block;
  width        : 14px;
  height       : 14px;
  border       : 2px solid currentColor;
  border-top-color: transparent;
  border-radius: 50%;
  animation    : btn-spin 0.7s linear infinite;
  flex-shrink  : 0;
}

@keyframes btn-spin {
  to { transform: rotate(360deg); }
}


/* ══════════════════════════════════════════════════════════
   BADGE
══════════════════════════════════════════════════════════ */

.btn-badge-wrap {
  position: relative;
  display : inline-flex;
}

.btn-badge {
  position        : absolute;
  top             : -6px;
  right           : -6px;
  background      : var(--color-danger);
  color           : #ffffff;
  font-size       : 10px;
  font-weight     : 600;
  font-family     : var(--btn-font-family);
  border-radius   : 999px;
  min-width       : 17px;
  height          : 17px;
  padding         : 0 4px;
  display         : flex;
  align-items     : center;
  justify-content : center;
  line-height     : 1;
  border          : 2px solid #ffffff;
  pointer-events  : none;
}


/* ══════════════════════════════════════════════════════════
   BUTTON GROUP
══════════════════════════════════════════════════════════ */

.btn-group {
  display      : inline-flex;
  border       : 1px solid var(--color-border);
  border-radius: var(--btn-radius-default);
  overflow     : hidden;
}

.btn-group .btn {
  border-radius: 0;
  border       : none;
  border-right : 1px solid var(--color-border);
}

.btn-group .btn:last-child {
  border-right: none;
}

.btn-group .btn.btn-group-active {
  background: var(--color-primary);
  color     : #ffffff;
}


/* ══════════════════════════════════════════════════════════
   DARK MODE
══════════════════════════════════════════════════════════ */

@media (prefers-color-scheme: dark) {
  :root {
    --color-primary      : #f9fafb;
    --color-primary-hover: #e5e7eb;
    --color-surface      : #1f2937;
    --color-surface-hover: #374151;
    --color-border       : #374151;
    --color-text         : #f9fafb;
    --color-text-muted   : #9ca3af;
    --ring-primary       : rgba(249, 250, 251, 0.25);
  }

  .btn-solid-primary { color: #111827; }

  .btn-soft-primary {
    background: rgba(255, 255, 255, 0.08);
    color     : #f9fafb;
  }
  .btn-soft-primary:hover:not(:disabled) { background: rgba(255, 255, 255, 0.14); }

  .btn-badge { border-color: #111827; }
}
